import React, { useState, useEffect } from 'react';
import { authService } from './services/auth.service';
import { firestoreService } from './services/firestore.service';
import './Dashboard.css';

interface UserStats {
  totalStudyHours: number;
  currentStreak: number;
  topicsMastered: number;
  flashcardsReviewed: number;
  badgesEarned: string[];
}

interface Flashcard {
  id: string;
  front: string;
  back: string;
  difficulty: 'easy' | 'medium' | 'hard';
}

interface CalendarEvent {
  date: string;
  type: 'exam' | 'revision' | 'pastpaper' | 'note';
  title: string;
  subject?: string;
}

interface DashboardProps {
  userName?: string;
  onLogout?: () => void;
  onThemeToggle?: () => void;
  theme?: 'light' | 'dark';
}

const Dashboard: React.FC<DashboardProps> = ({ userName: propUserName, onLogout, onThemeToggle, theme = 'light' }) => {
  // User data
  const [userName, setUserName] = useState(propUserName || 'Alex');
  const [userEmail, setUserEmail] = useState('');

  // User stats
  const [userStats, setUserStats] = useState<UserStats>({
    totalStudyHours: 0,
    currentStreak: 0,
    topicsMastered: 0,
    flashcardsReviewed: 0,
    badgesEarned: []
  });

  const [examsIn] = useState(42);
  const [todayMinutes] = useState(45);

  // Pomodoro timer
  const [pomodoroActive, setPomodoroActive] = useState(false);
  const [pomodoroTime, setPomodoroTime] = useState(25 * 60);
  const [isWorkSession, setIsWorkSession] = useState(true);

  // Flashcards
  const [flashcards, setFlashcards] = useState<Flashcard[]>([
    { id: '1', front: 'What is photosynthesis?', back: 'Process by which plants convert sunlight into chemical energy', difficulty: 'easy' },
    { id: '2', front: 'State Newtons First Law', back: 'An object at rest stays at rest and an object in motion stays in motion unless acted upon by an external force', difficulty: 'medium' },
    { id: '3', front: 'Define mitosis', back: 'Division of a cell nucleus resulting in two nuclei each having the same number and kind of chromosomes', difficulty: 'medium' }
  ]);

  // Calendar events
  const [calendarEvents, setCalendarEvents] = useState<CalendarEvent[]>([
    { date: '2026-04-15', type: 'exam', title: 'GCSE Maths Paper 1', subject: 'Maths' },
    { date: '2026-04-22', type: 'exam', title: 'GCSE Physics Paper 1', subject: 'Physics' },
    { date: '2026-05-02', type: 'exam', title: 'GCSE English Language Paper 1', subject: 'English Language' }
  ]);

  // UI state
  const [activeTab, setActiveTab] = useState<'dashboard' | 'flashcards' | 'calendar' | 'achievements'>('dashboard');
  const [loading, setLoading] = useState(true);

  // Load Firebase data on component mount
  useEffect(() => {
    const unsubscribe = authService.onAuthStateChanged(async (user) => {
      if (user) {
        try {
          // Set user email
          setUserEmail(user.email || '');

          // Load user profile from Firestore
          const profile = await firestoreService.getUserProfile(user.uid);
          if (profile) {
            setUserName(profile.displayName || 'User');
          }

          // Load user stats from Firestore
          const stats = await firestoreService.getUserStats(user.uid);
          if (stats) {
            setUserStats(stats);
          }

          // Load flashcard decks from Firestore
          try {
            const decks = await firestoreService.getFlashcardDecks(user.uid);
            console.log('Loaded flashcard decks:', decks);
            // You can process decks here if needed
          } catch (error) {
            console.log('No flashcard decks found yet (first time user)');
          }

          // Load calendar events from Firestore
          try {
            const events = await firestoreService.getCalendarEvents(user.uid);
            if (events && events.length > 0) {
              // Convert Firestore events to component format
              const formattedEvents = events.map((event: any) => ({
                date: event.date instanceof Date ? event.date.toISOString().split('T')[0] : event.date,
                type: event.type || 'note',
                title: event.title || 'Event',
                subject: event.subject
              }));
              setCalendarEvents(formattedEvents);
            }
          } catch (error) {
            console.log('No calendar events found yet');
          }

          console.log('User data loaded successfully');
        } catch (error) {
          console.error('Error loading user data:', error);
        }
      }
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  // Pomodoro timer logic
  useEffect(() => {
    let interval: NodeJS.Timeout;

    if (pomodoroActive && pomodoroTime > 0) {
      interval = setInterval(() => {
        setPomodoroTime(prev => prev - 1);
      }, 1000);
    } else if (pomodoroTime === 0 && pomodoroActive) {
      // Switch sessions
      if (isWorkSession) {
        setPomodoroTime(5 * 60); // 5 min break
        setIsWorkSession(false);
      } else {
        setPomodoroTime(25 * 60); // 25 min work
        setIsWorkSession(true);
      }
    }

    return () => clearInterval(interval);
  }, [pomodoroActive, pomodoroTime, isWorkSession]);

  // Helper functions
  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const togglePomodoro = () => {
    setPomodoroActive(!pomodoroActive);
  };

  const resetPomodoro = () => {
    setPomodoroActive(false);
    setPomodoroTime(25 * 60);
    setIsWorkSession(true);
  };

  const getDifficultyColor = (difficulty: string) => {
    switch (difficulty) {
      case 'easy':
        return '#10b981';
      case 'medium':
        return '#f59e0b';
      case 'hard':
        return '#ef4444';
      default:
        return '#6b7280';
    }
  };

  const handleLogout = async () => {
    if (onLogout) {
      onLogout();
    } else {
      try {
        await authService.signout();
      } catch (error) {
        console.error('Logout error:', error);
      }
    }
  };

  // Loading state
  if (loading) {
    return (
      <div style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        minHeight: '100vh',
        background: 'linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%)',
        fontSize: '16px',
        color: '#6b7280'
      }}>
        ⏳ Loading your dashboard...
      </div>
    );
  }

  // Render functions
  const renderDashboardTab = () => (
    <div className="dashboard-content">
      {/* Welcome Section */}
      <div className="welcome-section">
        <h2>Welcome back, {userName}! 👋</h2>
        <p>GCSE exams in {examsIn} days • Keep up your momentum</p>
        {userEmail && <p style={{ fontSize: '12px', color: '#9ca3af', margin: '4px 0 0 0' }}>{userEmail}</p>}
      </div>

      {/* Featured Card - Today's Focus */}
      <div className="featured-card">
        <div className="featured-header">
          <div>
            <div className="featured-label">Today's Study Plan</div>
            <div className="featured-value">{todayMinutes} mins</div>
          </div>
          <div className="featured-icon">📚</div>
        </div>
        <div className="featured-action">
          <button 
            className={`pomodoro-btn ${pomodoroActive ? 'active' : ''}`}
            onClick={togglePomodoro}
          >
            {pomodoroActive ? '⏸ Pause' : '▶ Start Pomodoro'}
          </button>
          {pomodoroActive && (
            <button className="reset-btn" onClick={resetPomodoro}>↻</button>
          )}
        </div>
      </div>

      {/* Stats Grid */}
      <div className="stats-grid">
        {/* Today's Study Session */}
        <div className="stat-card">
          <div className="stat-label">Study time today</div>
          <div className="stat-value">{todayMinutes} mins</div>
          <div className="stat-detail">3 sessions completed</div>
        </div>

        {/* Current Streak */}
        <div className="stat-card streak-card">
          <div className="stat-label">Current Streak 🔥</div>
          <div className="stat-value">{userStats.currentStreak} days</div>
          <div className="stat-detail">Keep it up!</div>
        </div>

        {/* Topics Mastered */}
        <div className="stat-card">
          <div className="stat-label">Topics Mastered</div>
          <div className="stat-value">{userStats.topicsMastered}/48</div>
          <div className="progress-bar">
            <div 
              className="progress-fill" 
              style={{width: `${(userStats.topicsMastered / 48) * 100}%`}}
            ></div>
          </div>
        </div>

        {/* Flashcards Reviewed */}
        <div className="stat-card">
          <div className="stat-label">Flashcards</div>
          <div className="stat-value">{userStats.flashcardsReviewed}</div>
          <div className="stat-detail">Cards reviewed</div>
        </div>
      </div>

      {/* Quick Action Cards */}
      <div className="quick-actions-grid">
        <div className="action-card action-flashcards" onClick={() => setActiveTab('flashcards')}>
          <div className="action-icon">📝</div>
          <div className="action-title">Flashcards</div>
          <div className="action-subtitle">{flashcards.length} cards ready</div>
        </div>

        <div className="action-card action-pastpapers">
          <div className="action-icon">📄</div>
          <div className="action-title">Past Papers</div>
          <div className="action-subtitle">Practice 1-3 marks</div>
        </div>

        <div className="action-card action-calendar" onClick={() => setActiveTab('calendar')}>
          <div className="action-icon">📅</div>
          <div className="action-title">Calendar</div>
          <div className="action-subtitle">{calendarEvents.length} exams scheduled</div>
        </div>

        <div className="action-card action-resources">
          <div className="action-icon">🔗</div>
          <div className="action-title">Resources</div>
          <div className="action-subtitle">Maths Genie + 7 more</div>
        </div>
      </div>

      {/* Upcoming Exams */}
      <div className="upcoming-section">
        <h3>Upcoming Exams</h3>
        <div className="exam-list">
          {calendarEvents
            .filter(e => e.type === 'exam')
            .map((exam, idx) => (
              <div key={idx} className="exam-item">
                <div className="exam-date">{new Date(exam.date).toLocaleDateString('en-GB', { month: 'short', day: 'numeric' })}</div>
                <div className="exam-details">
                  <div className="exam-title">{exam.title}</div>
                  <div className="exam-subject">{exam.subject}</div>
                </div>
                <div className="exam-days-left">
                  {Math.ceil((new Date(exam.date).getTime() - new Date().getTime()) / (1000 * 60 * 60 * 24))} days
                </div>
              </div>
            ))}
        </div>
      </div>
    </div>
  );

  const renderFlashcardsTab = () => (
    <div className="flashcards-content">
      <h2>Flashcards</h2>
      <div className="flashcards-grid">
        {flashcards.map((card) => (
          <div key={card.id} className="flashcard" style={{ borderLeftColor: getDifficultyColor(card.difficulty) }}>
            <div className="card-difficulty">{card.difficulty.toUpperCase()}</div>
            <div className="card-front">{card.front}</div>
            <div className="card-back">{card.back}</div>
          </div>
        ))}
      </div>
      <button className="create-btn">+ Create New Deck</button>
    </div>
  );

  const renderCalendarTab = () => (
    <div className="calendar-content">
      <h2>Calendar</h2>
      <div className="calendar-events">
        {calendarEvents.map((event, idx) => (
          <div key={idx} className={`calendar-event event-${event.type}`}>
            <div className="event-icon">
              {event.type === 'exam' && '📝'}
              {event.type === 'revision' && '📚'}
              {event.type === 'pastpaper' && '📄'}
              {event.type === 'note' && '📌'}
            </div>
            <div className="event-info">
              <div className="event-date">{new Date(event.date).toLocaleDateString('en-GB', { weekday: 'long', month: 'long', day: 'numeric' })}</div>
              <div className="event-title">{event.title}</div>
              {event.subject && <div className="event-subject">{event.subject}</div>}
            </div>
          </div>
        ))}
      </div>
      <button className="create-btn">+ Add Event</button>
    </div>
  );

  const renderAchievementsTab = () => (
    <div className="achievements-content">
      <h2>Achievements</h2>
      <div className="achievements-grid">
        {userStats.badgesEarned.map((badge) => (
          <div key={badge} className="badge">
            <div className="badge-emoji">🏆</div>
            <div className="badge-name">{badge.replace('_', ' ').toUpperCase()}</div>
          </div>
        ))}
        {userStats.badgesEarned.length === 0 && (
          <div className="badge locked">
            <div className="badge-emoji">🔒</div>
            <div className="badge-name">START STUDYING</div>
          </div>
        )}
        <div className="badge locked">
          <div className="badge-emoji">🔒</div>
          <div className="badge-name">UNLOCK MORE</div>
        </div>
      </div>
    </div>
  );

  return (
    <div className="dashboard-container">
      {/* Header */}
      <header className="dashboard-header">
        <div className="header-left">
          <h1>📚 ReviseHub</h1>
          <p>GCSE Revision Assistant</p>
        </div>
        <div className="header-right">
          <div className="streak-badge">
            <div className="streak-emoji">🔥</div>
            <div className="streak-text">{userStats.currentStreak} days</div>
          </div>
          <button 
            onClick={handleLogout}
            style={{
              background: 'rgba(255,255,255,0.2)',
              border: '1px solid rgba(255,255,255,0.3)',
              color: 'white',
              padding: '8px 14px',
              borderRadius: '8px',
              cursor: 'pointer',
              fontSize: '13px',
              fontWeight: '500',
              transition: 'all 0.3s ease'
            }}
            onMouseOver={(e) => {
              e.currentTarget.style.background = 'rgba(255,255,255,0.3)';
            }}
            onMouseOut={(e) => {
              e.currentTarget.style.background = 'rgba(255,255,255,0.2)';
            }}
          >
            Sign Out
          </button>
          <button 
            onClick={onThemeToggle}
            style={{
              background: 'rgba(255,255,255,0.2)',
              border: '1px solid rgba(255,255,255,0.3)',
              color: 'white',
              padding: '8px 14px',
              borderRadius: '8px',
              cursor: 'pointer',
              fontSize: '16px',
              marginRight: '12px',
              transition: 'all 0.3s ease'
            }}
            onMouseOver={(e) => {
              e.currentTarget.style.background = 'rgba(255,255,255,0.3)';
            }}
            onMouseOut={(e) => {
              e.currentTarget.style.background = 'rgba(255,255,255,0.2)';
            }}
            title={`Switch to ${theme === 'light' ? 'dark' : 'light'} mode`}
          >
            {theme === 'light' ? '🌙' : '☀️'}
          </button>
        </div>
      </header>

      {/* Pomodoro Timer Display */}
      {pomodoroActive && (
        <div className="pomodoro-display">
          <div className="pomodoro-time">{formatTime(pomodoroTime)}</div>
          <div className="pomodoro-session">{isWorkSession ? '🎯 Work Session' : '☕ Break Time'}</div>
        </div>
      )}

      {/* Navigation Tabs */}
      <nav className="dashboard-nav">
        <button 
          className={`nav-tab ${activeTab === 'dashboard' ? 'active' : ''}`}
          onClick={() => setActiveTab('dashboard')}
        >
          📊 Dashboard
        </button>
        <button 
          className={`nav-tab ${activeTab === 'flashcards' ? 'active' : ''}`}
          onClick={() => setActiveTab('flashcards')}
        >
          📝 Flashcards
        </button>
        <button 
          className={`nav-tab ${activeTab === 'calendar' ? 'active' : ''}`}
          onClick={() => setActiveTab('calendar')}
        >
          📅 Calendar
        </button>
        <button 
          className={`nav-tab ${activeTab === 'achievements' ? 'active' : ''}`}
          onClick={() => setActiveTab('achievements')}
        >
          🏆 Achievements
        </button>
      </nav>

      {/* Main Content */}
      <main className="dashboard-main">
        {activeTab === 'dashboard' && renderDashboardTab()}
        {activeTab === 'flashcards' && renderFlashcardsTab()}
        {activeTab === 'calendar' && renderCalendarTab()}
        {activeTab === 'achievements' && renderAchievementsTab()}
      </main>

      {/* Footer */}
      <footer className="dashboard-footer">
        <p>Keep studying! You're making great progress. 🎉</p>
      </footer>
    </div>
  );
};

export default Dashboard;
